void reply(WebServer* server, int code, PGM_P content_type, PGM_P content, size_t contentLength) {
    server->sendHeader("Content-Encoding", "gzip");
    server->send_P(code, content_type, content, contentLength);
}

void initWebServer() {
    initRoutes();
    server.begin();
    Serial.println("HTTP server started !");
}

void initRoutes() {
    server.on("/", HTTP_GET, handleIndex);
    server.on("/index.html", HTTP_GET, handleIndex);
    server.on("/main.js", HTTP_GET, handleJS);
    server.on("/style.css", HTTP_GET, handleCSS);
    server.on("/run", HTTP_POST, handleDuckyScript);
    server.onNotFound(handle404);
}

void handleIndex() {
    reply(&server, 200, "text/html", PAGE_INDEX_GZ, sizeof(PAGE_INDEX_GZ));
}

void handleJS() {
    reply(&server, 200, "application/javascript", PAGE_JS_GZ, sizeof(PAGE_JS_GZ));
}

void handleCSS() {
    reply(&server, 200, "text/css", PAGE_CSS_GZ, sizeof(PAGE_CSS_GZ));
}

void handleDuckyScript() {
    if (server.hasArg("script")) {
        String script = server.arg("script");
        Serial.printf("Script recieved: %s\n", script.c_str());
        
        bool success = duckyparser::execute(script);

        if (success) {
            server.send(200, "text/html", "Script executed successfully.");
        } else {
            server.send(400, "text/html", "Error: Invalid script.");
        }

    } else {
        server.send(400, "text/html", "Error: missing script parameter.");
    }
}

void handle404() {
    reply(&server, 404, "text/html", PAGE_404_GZ, sizeof(PAGE_404_GZ));
}
